'use client';

import { useEffect } from 'react';
import type { ThemeType } from './NextThemeProvider.types';

interface ThemeScriptProps {
	theme: ThemeType;
}

/**
 * Клиентский компонент для применения темы к body
 * Используется внутри серверного NextThemeProvider
 */
export function ThemeScript({ theme }: ThemeScriptProps) {
	useEffect(() => {
		const themeClass = theme === 'light' ? 'ds-theme--light' : 'ds-theme--dark';

		// Удаляем старые классы темы
		document.body.classList.remove('ds-theme--light', 'ds-theme--dark');
		// Добавляем новый класс темы
		document.body.classList.add(themeClass);
	}, [theme]);

	return null; // Не рендерим ничего
}
